+void* TestThread::Entry()
+{
+  wxLogMessage(_T("Conducting self test...\n"));
+
+  if (ros::service::call("urglaser/self_test", parent->req, parent->res))
+  {
+    wxLogMessage(_T("Self test completed\n") + wxString::FromAscii(parent->res.info.c_str()));
