+void HokuyoTester::OnMouse(wxMouseEvent& event)
+{
+  int x, y;
+  event.GetPosition(&x,&y);
+
+  int dx, dy;
+  dx = x - last_x;
+  dy = y - last_y;
+
+  last_x = x;
+  last_y = y;
+
+  if (event.LeftIsDown())
+  {
+    view_x += dx / view_scale;
+    view_y -= dy / view_scale;
+
+    wxPaintEvent* e = new wxPaintEvent();
+    gl->AddPendingEvent(*e);
+  }
+  if (event.RightIsDown())
+  {
+    view_scale *= 1.0 - dy * 0.01;
+
+    wxPaintEvent* e = new wxPaintEvent();
+    gl->AddPendingEvent(*e);
+  }
+}
